<script>
    const queryString = window.location.search;
    const urlParams = new URLSearchParams(queryString);
    const branchId = urlParams.get('id');
    const startYear = urlParams.get('startYear');
    const currencyFocus = urlParams.get('currencyId');

    $("#all_period_criteria").on("change", function() {
        $(".period_criteria").prop("checked", $(this).prop("checked")).trigger('change');
    }).trigger('change');

    // ถ้าทุก checkbox ถูกเลือก ให้ติ๊กอัตโนมัติ "Checked All"
    $(".period_criteria").on("change", function() {
        if ($(".period_criteria:checked").length === $(".period_criteria").length) {
            $("#all_period_criteria").prop("checked", true);
        } else {
            $("#all_period_criteria").prop("checked", false);
        }

        let selectClass = $(this).data('class');
        if ($(this).is(':checked')) {
            $(selectClass).show();
        } else {
            $(selectClass).hide();
        }

        let firstCheckedClass = null;

        $(".period_criteria:checked").each(function() {
            const dataClass = $(this).data("class");
            if (!firstCheckedClass) {
                firstCheckedClass = dataClass;
            }
        });

        if (!firstCheckedClass) {
            console.warn("❗ ไม่มีคอลัมน์ที่ถูกเลือกอยู่เลย");
            return;
        }

        // วนลูปทุกแถว แล้วใส่ .show แค่ในคอลัมน์แรกที่เลือก
        $(".table-data-pl").each(function() {
            $(this).find("tr").each(function() {
                const $cells = $(this).find(".data-pl");

                $cells.removeClass("show");

                const $target = $cells.filter(firstCheckedClass);
                if ($target.length > 0 && $target.is(":visible")) {
                    $target.first().addClass("show");
                }
            });
        });



    }).trigger('change');

