    function updateCollapse() {
        // ✅ ใช้ $(document).on() แทน $(".xxx").click()
        $(document).on("click", ".collapse-all", function(e) {

            if ($(".table-data-pl").length > 0 && $(".table-data-pl").not(".collapse-pl").length === 0) {
                $('.table-data-pl').removeClass('collapse-pl');
            } else {
                $('.table-data-pl').addClass('collapse-pl');
            }
            if ($(".table-data-pl").not(".collapse-pl").length !== 0) {
                $("#text-expand").hide();
                $("#text-collapse").show();
            } else {
                $("#text-expand").show();
                $("#text-collapse").hide();
            }
            setWidthTable();
        });

        $(document).on("click", ".row-collapse", function(e) {
            $(this).parents('table').addClass('collapse-pl');
            if ($(".table-data-pl").not(".collapse-pl").length !== 0) {
                $("#text-expand").hide();
                $("#text-collapse").show();
            } else {
                $("#text-expand").show();
                $("#text-collapse").hide();
            }
            setWidthTable();
        });

        $(document).on("click", ".ex-collapse", function(e) {
            $(this).parents('table').removeClass('collapse-pl');
            if ($(".table-data-pl").not(".collapse-pl").length !== 0) {
                $("#text-expand").hide();
                $("#text-collapse").show();
            } else {
                $("#text-expand").show();
                $("#text-collapse").hide();
            }
            setWidthTable();
        });

        $(document).on("click", ".btn-show-data", function(e) {
            let updateHtml = $(this).data('target');
            if ($(this).hasClass('show')) {
                $(this).removeClass('show');
                $(updateHtml + ' td').css('opacity', 0);
            } else {
                $(this).addClass('show');
                $(updateHtml + ' td').css('opacity', 1);
            }
        });

        // $(document).on("click", ".table-data-pl.collapse-pl th.data-pl.show", function() {
        //     let table = $(this).closest("table");
        //     let allRows = table.find("thead tr, tbody tr");

        //     allRows.each(function() {
        //         let $showCell = $(this).find(".data-pl.show");

        //         if ($showCell.length) {
        //             let nextCell = $showCell.next(".data-pl");
        //             if (nextCell.length === 0) {
        //                 nextCell = $(this).find(".data-pl").first();
        //             }
        //             $showCell.removeClass("show");
        //             nextCell.addClass("show");
        //         }
        //     });
        //     setWidthTable();
        // });

        $(document).on("click", ".table-data-pl.collapse-pl th.data-pl.show", function() {
            // 1. ดึง list ของ class ที่ยัง checked อยู่ เช่น [".content-pl", ".content-cp"]
            let activeClasses = $(".period_criteria:checked")
                .map(function() {
                    return $(this).data("class");
                })
                .get();

            if (activeClasses.length === 0) {
                console.warn("❗ ไม่มีคอลัมน์ที่เปิดอยู่เลย");
                return; // 👉 ไม่ทำอะไรถ้าไม่มี filter ถูกเลือก
            }

            let table = $(this).closest("table");
            let allRows = table.find("thead tr, tbody tr");

            allRows.each(function() {
                let $cells = $(this).find(".data-pl");
                let $current = $cells.filter(".show");

                // เอา class ปัจจุบันออกก่อน
                $current.removeClass("show");

                // หา cell ถัดไปที่อยู่ใน activeClasses และวนรอบ
                let currentIndex = $cells.index($current);
                let total = $cells.length;

                for (let i = 1; i <= total; i++) {
                    let nextIndex = (currentIndex + i) % total;
                    let $nextCell = $cells.eq(nextIndex);

                    // ถ้า cell ถัดไปตรงกับ class ที่เปิดอยู่
                    for (let j = 0; j < activeClasses.length; j++) {
                        if ($nextCell.hasClass(activeClasses[j].replace('.', ''))) {
                            $nextCell.addClass("show");
                            return;
                        }
                    }
                }

                // fallback: ถ้าไม่เจอเลย ใส่ show ที่ตัวเดิม (หรือข้ามก็ได้)
                $current.addClass("show");
            });

            setWidthTable();
        });

    }

    function getHead() {
        let year = $("#year").val();
        let rate = $("#rate").val();
        let quarter = $("#quarter").val();
        let currencyId = $("#currencyId").val();
        $.ajax({
            url: "ajax/FinancialProfitLossPortal/getHead.php",
            type: 'POST',
            dataType: 'html',
            data: {
                year: year,
                branchId: branchId,
                rate: rate,
                quarter: quarter,
                currencyId: currencyId,
            },
            success: function(data) {
                Swal.close();
                $('#showHead').html(data);

                $(".donut-chart").each(function() {
                    let calPercentPlus = Math.floor($(this).data('percent'));
                    let calPercentMinus = 100 - calPercentPlus;

                    let colorActive = "#000"; // สีเริ่มต้น (กรณีไม่มี class ที่ตรง)
                    let colorInActive = "#ccc"; // สีเริ่มต้น

                    if ($(this).hasClass('donut-red')) {
                        colorActive = "#fa3246";
                        colorInActive = "#fabcc2";
                    }
                    if ($(this).hasClass('donut-green')) {
                        colorActive = "#2ca46c";
                        colorInActive = "#b0cfc1";
                    }
                    if ($(this).hasClass('donut-yellow')) {
                        colorActive = "#ffc107";
                        colorInActive = "#f9e6ad";
                    }
                    if ($(this).hasClass('donut-blue')) {
                        colorActive = "#3b3dfa";
                        colorInActive = "#cccdf5";
                    }

                    $(this).css(
                        'background',
                        `conic-gradient(${colorActive} 0% ${calPercentPlus}%, ${colorInActive} ${calPercentPlus}% 100%)`
                    ).html(`<div class="donut-chart-label">${calPercentPlus}%</div>`);
                });

                $('#filter-fs-middle').removeClass('active');
                // ✅ เรียก updateCollapse() หลังจากอัปเดต HTML
                // updateCollapse();


                $("#text-expand").hide();
                $("#text-collapse").show();

            },
            error: function(jqXHR, exception) {
                var msg = '';
                if (jqXHR.status === 0) {
                    msg = 'Not connect. Verify Network.';
                } else if (jqXHR.status == 404) {
                    msg = 'Requested page not found. [404]';
                } else if (jqXHR.status == 500) {
                    msg = 'Internal Server Error [500].';
                } else if (exception === 'parsererror') {
                    msg = 'Requested JSON parse failed.';
                } else if (exception === 'timeout') {
                    msg = 'Time out error.';
                } else if (exception === 'abort') {
                    msg = 'Ajax request aborted.';
                } else {
                    msg = 'Uncaught Error. ' + jqXHR.responseText;
                }

                Swal.fire({
                    title: 'Warning !',
                    text: "There was a recording problem. Please contact the system administrator. " + msg,
                    icon: 'error',
                    showConfirmButton: false,
                    timer: 1500
                });
            }
        });
    }

    $.extend({
        redirectPost: function(location, args) {
            var form = '';
            $.each(args, function(key, value) {
                form += '<input type="hidden" name="' + key + '" value="' + value + '">';
            });
            $('<form action="' + location + '" method="POST">' + form + '</form>').appendTo('body')
                .submit();
        }
    });

    function exportExcel() {
        let year = $("#year").val();
        let rate = $("#rate").val();
        let quarter = $("#quarter").val();
        let currencyId = $("#currencyId").val();

        let periodCriteria = [];
        $("input[name='period_criteria[]']:checked").each(function() {
            periodCriteria.push($(this).val());
        });

        let plCategory = [];
        $("input[name='pl_category[]']:checked").each(function() {
            plCategory.push($(this).val());
        });

        var redirect = 'ajax/FinancialProfitLossPortal/exportMainExcel.php';

        $.redirectPost(redirect, {
            year: year,
            branchId: branchId,
            rate: rate,
            quarter: quarter,
            currencyId: currencyId,
            "period_criteria[]": periodCriteria,
            "pl_category[]": plCategory,
        });
    }

