    function importData() {
        let excelFile = $('#fileImport').val();

        if (excelFile == '') {
            alert('please upload excel file!!')
            return false;
        }

        let formData = new FormData($("#formImport")[0]);
        formData.append('branchId', branchId)

        customAlert({
            title: "Warning",
            message: "Do you want to save?",
            icon: "warning",
            confirmText: "Save",
            confirmColor: "btn-primary",
            cancelText: "Cancel",
            cancelColor: "btn-outline-secondary"
        }).then(() => {
            $.ajax({
                url: 'ajax/FinancialProfitLossPortalEdit/importData.php',
                type: 'POST',
                dataType: 'json',
                data: formData,
                cache: false,
                contentType: false,
                processData: false,
                success: function(response) {
                    if (response.result == 0) {
                        Swal.fire({
                            icon: "error",
                            title: "An error occurred !",
                            text: "Please check the file.",
                            showConfirmButton: false,
                            timer: 1500
                        }).then((data) => {
                            window.open("ajax/FinancialProfitLossPortalEdit/ErrorFiles.xlsx", '_blank');
                        });
                    } else if (response.result == 1) {
                        customAlert({
                            title: "Success!",
                            message: "Your action was successful.",
                            icon: "success",
                            timer: 1500
                        }).then(() => {
                            location.reload();
                        });
                    }
                },
                error: function(jqXHR, exception) {
                    var msg = '';
                    if (jqXHR.status === 0) {
                        msg = 'Not connect. Verify Network.';
                    } else if (jqXHR.status == 404) {
                        msg = 'Requested page not found. [404]';
                    } else if (jqXHR.status == 500) {
                        msg = 'Internal Server Error [500].';
                    } else if (exception === 'parsererror') {
                        msg = 'Requested JSON parse failed.';
                    } else if (exception === 'timeout') {
                        msg = 'Time out error.';
                    } else if (exception === 'abort') {
                        msg = 'Ajax request aborted.';
                    } else {
                        msg = 'Uncaught Error. ' + jqXHR.responseText;
                    }

                    Swal.fire({
                        title: 'Warning !',
                        text: "There was a recording problem. Please contact the system administrator. " + msg,
                        icon: 'error',
                        showConfirmButton: false,
                        timer: 1500
                    });
                }
            });
        });
    }

    function setWidthTable() {

        let maxWidth = 0;

        if ($(".table-data-pl").not(".collapse-pl").length === 0) {
            $('.table-data-pl').each(function() {
                let width = $(this).outerWidth();
                if (width > maxWidth) {
                    maxWidth = width;
                }
            });
            $('.table-data-pl').css('width', maxWidth + 'px');
        } else {
            $('.table-data-pl').css('width', 'auto');

        }
    }
</script>